package sdjwtvc

import (
	"testing"

	"github.com/stretchr/testify/require"
)

func Test_SplitSdJwtVc_Succeeds(t *testing.T) {
	// Arrange
	expectedDisclosures := []EncodedDisclosure{
		"WyJMbm1Uem5RUVllTnpWbXBBWEFGVURBIiwiZW1haWwiLCJ0ZXN0QGdtYWlsLmNvbSJd",
		"WyJfY1ZvUU9yd3JrYUhaUTVWeGZtQlVnIiwiZG9tYWluIiwiZ21haWwuY29tIl0",
	}

	// Act
	issuerSignedJwt, encodedDisclosures, err := splitSdJwtVc(validSdJwtVc_DcTypHeader_WithoutKbJwt)

	// Assert
	require.NoError(t, err)
	require.Equal(t, "..gxk7xIH9hpkhzBohsZMGpX_18pQd_NnJ_1n3C4Rl4qxSiDvXQ4LsP8wrBl1S-shgjTovgBefvYTgaJzTTzR9zQ", string(issuerSignedJwt))
	require.ElementsMatch(t, expectedDisclosures, encodedDisclosures)
}

func Test_SplitSdJwtVc_GivenIssuerSignedJwt_WithoutTrailingSlash_Succeeds(t *testing.T) {
	// Arrange
	jwt := SdJwtVc("..qrAancJmSTjfkBz-uad3wxH91ogaM1Su7rr_nowQoayvblJYeamBcwcZMNeRq_kqaAq4N12XbBImKR8VrXEoow")

	// Act
	_, _, err := splitSdJwtVc(jwt)

	// Assert
	require.NoError(t, err)
}

func Test_SplitSdJwtVc_SdJwtWithSingleDisclosure_WithoutTrailingSlash_Fails(t *testing.T) {
	// Arrange
	jwt := SdJwtVc("..qrAancJmSTjfkBz-uad3wxH91ogaM1Su7rr_nowQoayvblJYeamBcwcZMNeRq_kqaAq4N12XbBImKR8VrXEoow~WyI2ajdiNWh2bE9lazFfVm9XSVRPVVV3IiwiZW1haWwiLCJ0ZXN0QGdtYWlsLmNvbSJd")

	// Act
	_, _, err := splitSdJwtVc(jwt)

	// Assert
	require.NoError(t, err)
}
